import{_ as r,c as d,o as e,ag as o}from"./chunks/framework.DRADY2L-.js";const h=JSON.parse('{"title":"FPV Glossary","description":"This glossary explains common Russian FPV slang terms and abbreviations used in the FPV drone community. | Term (Russian) | Meaning (English) | | -----------...","frontmatter":{"description":"This glossary explains common Russian FPV slang terms and abbreviations used in the FPV drone community. | Term (Russian) | Meaning (English) | | -----------...","gitAuthors":["mituritsyn"]},"headers":[],"relativePath":"intro/glossarium.md","filePath":"en/intro/glossarium.md","lastUpdated":1770586224000}'),a={name:"intro/glossarium.md"};function i(s,t,n,l,m,c){return e(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="fpv-glossary" tabindex="-1">FPV Glossary <a class="header-anchor" href="#fpv-glossary" aria-label="Permalink to &quot;FPV Glossary&quot;">​</a></h1><p>This glossary explains common Russian FPV slang terms and abbreviations used in the FPV drone community.</p><table tabindex="0"><thead><tr><th>Term (Russian)</th><th>Meaning (English)</th></tr></thead><tbody><tr><td>ЛА (LA)</td><td>aircraft / flying vehicle</td></tr><tr><td>ВМГ (VMG)</td><td>propeller-motor group (motor + propeller assembly)</td></tr><tr><td>2&quot;, 2.5&quot;, 3&quot;, 3.5&quot;, 4&quot;, 5&quot;, 6&quot;, 7&quot; ..</td><td>propeller diameter, used to designate drone size classes</td></tr><tr><td>31mm, 35mm, 40mm, 45mm</td><td>propeller diameter smaller than 2&quot;, mainly used among tiny whoops</td></tr><tr><td>tiny whoop, тинивуп, вуп (tinywhoop, whoop)</td><td>tiny copter with 65-75mm diagonal motor-to-motor distance, prop guards on frame, powered by 1-2S battery</td></tr><tr><td>синик, синевуп (cinewhoop)</td><td>from &quot;cinematic&quot; - copter for smooth flights to capture cinematic footage, with prop guards/ducts</td></tr><tr><td>зубочистка (toothpick)</td><td>very lightweight copter</td></tr><tr><td>батка, бата, АКБ, аккум, батарея (battery)</td><td>battery</td></tr><tr><td>4ы, 4s (4S)</td><td>number of battery cells, in this example 4; each cell has 4.2V maximum voltage for LiPo/LiOn, or 4.35V for LiHV</td></tr><tr><td>LiPo, LiOn/LiIon, липо, лион</td><td>most common types of lithium batteries</td></tr><tr><td>LiHV, лихв, хв батка</td><td>lithium high voltage, battery with increased voltage, max 4.35V per cell, mainly used for tiny whoops</td></tr><tr><td>ирл, IRL</td><td>In Real Life</td></tr><tr><td>FPV</td><td>First Person View</td></tr><tr><td>OSD</td><td>On Screen Display</td></tr><tr><td>KV</td><td>RPM per volt (motor constant)</td></tr><tr><td>TVL</td><td>TV Lines - analog camera resolution specification</td></tr><tr><td>сетап, билд, сборка (setup, build)</td><td>refers to a complete copter build</td></tr><tr><td>стек, стак (stack)</td><td>tower of 4-in-1 ESC with flight controller, sometimes with video transmitter</td></tr><tr><td>канопа (canopy)</td><td>upper frame cover, typically plastic, protecting electronics</td></tr><tr><td>маунт (mount)</td><td>mounting hardware for camera, antenna, etc.</td></tr><tr><td>tx</td><td>transmitter, sends signal (can be a separate device or a transmitting pin on a board)</td></tr><tr><td>rx</td><td>receiver, receives signal (can be a separate device or a receiving pin on a board)</td></tr><tr><td>втх, vtx</td><td>video transmitter</td></tr><tr><td>рег, esc</td><td>ESC (Electronic Speed Controller)</td></tr><tr><td>приемыш (receiver)</td><td>radio receiver (slang)</td></tr><tr><td>передаст (transmitter)</td><td>radio transmitter (slang)</td></tr><tr><td>пк, мозг (FC, brain)</td><td>flight controller</td></tr><tr><td>редиска (radish)</td><td>a bad person (Russian slang, not really FPV-specific)</td></tr><tr><td>камень (stone)</td><td>microprocessor, STM chip</td></tr><tr><td>кондер (cap)</td><td>capacitor</td></tr><tr><td>резюк (resistor)</td><td>resistor</td></tr><tr><td>проп (prop)</td><td>propeller</td></tr><tr><td>аппа (radio)</td><td>radio transmitter / controller</td></tr><tr><td>бут, boot, дфу, дфю (boot, DFU)</td><td>bootloader mode, typically activated by holding the boot button while powering on</td></tr><tr><td>клипса (c-clip)</td><td>c-clip / e-clip</td></tr><tr><td>пантилт, pan-tilt</td><td>pan-tilt system for antennas, etc.</td></tr><tr><td>диверсити (diversity)</td><td>two receivers to output video from the source with better signal</td></tr><tr><td>кубик (cube)</td><td>action camera</td></tr><tr><td>серва (servo)</td><td>servo motor</td></tr><tr><td>пвм, pwm</td><td>PWM (Pulse Width Modulation)</td></tr><tr><td>ппм, сбас (ppm, sbus)</td><td>radio control protocols</td></tr><tr><td>аккст, аксес (ACCESS, ACCST)</td><td>FrSky protocol variants</td></tr><tr><td>бинд (bind)</td><td>process of linking a radio receiver to a transmitter; also applies to digital video systems</td></tr><tr><td>елрс, кросс, трейсер, гост (ELRS, Crossfire, Tracer, Ghost)</td><td>radio control systems, more info: <a href="https://propwashservice.com/intro/tx.html" target="_blank" rel="noreferrer">https://propwashservice.com/intro/tx.html</a></td></tr><tr><td>ксв (SWR)</td><td>Standing Wave Ratio - ratio of maximum to minimum voltage amplitude in a transmission line</td></tr><tr><td>бетка (Betaflight)</td><td>Betaflight firmware</td></tr><tr><td>ченл мап (channel map)</td><td>channel order field in Betaflight configurator&#39;s receiver section; abbreviation made from first letters of channel names in the transmitter&#39;s mixes</td></tr><tr><td>акро, стаб, горайзн (acro, stab, horizon)</td><td>flight stabilization modes</td></tr><tr><td>фс, fail safe, фейлсейф, фэйлсэйф</td><td>drone actions on signal loss: drop (motor shutoff), land (landing - rarely used), GPS rescue (return home with auto-landing from BF 4.4+); in INAV: RTH (return to home)</td></tr><tr><td>таргет (target)</td><td>device configuration file used for firmware compilation</td></tr><tr><td>пассфру, пассру, пастру, пасстру (passthrough)</td><td>passthrough - mode for transmitting serial data to a device connected to the FC&#39;s UART/SoftSerial port</td></tr><tr><td>десинк, срыв синхры (desync)</td><td>situation when ESC loses track of motor coil commutation, causing the motor to stop; usually happens with rapid RPM changes; sometimes fixable via ESC settings</td></tr><tr><td>тайминги (timing)</td><td>angle at which the magnet should lag when energizing the coil - related to brushless motor operation</td></tr><tr><td>питч, ролл, яв, тротл (pitch, roll, yaw, throttle)</td><td>axis names controlled by the sticks</td></tr><tr><td>пагода, патч, сосиска (pagoda, patch, sausage)</td><td>types of FPV antennas</td></tr><tr><td>рилка (Reelsteady)</td><td>Reelsteady GO - software stabilization for GoPro video</td></tr><tr><td>накед, голая проха (naked GoPro)</td><td>&quot;naked&quot; GoPro - stripped-down GoPro Hero camera, weight reduced from 120g to 26g, powered by 5V BEC instead of battery</td></tr><tr><td>софтмаунт, демпфер (softmount, damper)</td><td>vibration isolation mount</td></tr><tr><td>кз, коза (short)</td><td>short circuit</td></tr><tr><td>синий дым (magic blue smoke)</td><td>the magic that makes all electronics work; when it escapes, something burns out</td></tr><tr><td>спинер жижа (conformal coating)</td><td>Spinner protection silicone conformal coating, based on MG CHEMICALS 422B</td></tr><tr><td>т12, тс100 (T12, TS100)</td><td>popular soldering iron models with T12 and TS tips respectively</td></tr><tr><td>редитускай (Readytosky)</td><td>Chinese brand that typically makes clones of known brands with their own logo</td></tr><tr><td>колобок (kolobok)</td><td>frame from Aerodyne-RC (also nickname of the author in some circles)</td></tr><tr><td>пигтейл (pigtail)</td><td>coaxial cable adapter</td></tr><tr><td>армиться, арм (arm)</td><td>mode to start motors at minimum throttle (throttle must be at bottom); without arming, the drone won&#39;t fly</td></tr><tr><td>дизармиться, дизарм (disarm)</td><td>turn off motors regardless of throttle level</td></tr><tr><td>джи, джедай, цифра (DJI, digital)</td><td>DJI digital FPV system</td></tr><tr><td>толстяк (fattie)</td><td>DJI FPV Drone</td></tr><tr><td>волки, улитка, аватар (Walksnail, Avatar)</td><td>Walksnail Avatar digital video system (a division of Caddx FPV)</td></tr></tbody></table>',3)])])}const u=r(a,[["render",i]]);export{h as __pageData,u as default};
